#include <stdio.h>
#include <limits.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long minVal = LLONG_MAX; long long cntMin = 0;
        for(int i=0;i<N;i++){
            long long x; scanf("%lld", &x);
            if(x < minVal){
                minVal = x; cntMin = 1;
            } else if(x == minVal){
                cntMin++;
            }
        }
        long long ans = minVal * N + (N - cntMin);
        printf("%lld\n", ans);
    }
    return 0;
}

